import json
import boto3
import urllib.parse as urlparse
from botocore.vendored import requests

s3 = boto3.client('s3')

def lambda_handler(event, context):
    # Get the request headers from the event
    request_headers = event['request']

    # Check if the X-Enrich-URL header is present in the request
    if 'X-Enrich-URL' in request_headers:
        # Parse the URL from the header value
        url = urlparse.urlparse(request_headers['X-Enrich-URL'])

        # Make a GET request to the URL using the requests library
        response = requests.get(url)

        # If the response is successful, extract the data and add it to the event
        if response.status_code == 200:
            data = json.loads(response.content)
            event['data'] = data

    return event